QRCodeMessage.regexp = {
  numeric:/^\d+$/,
  alphanumeric:/^([A-Z]|\d| |\$|%|\*|\+|-|\.|\/|:)+$/,
}
QRCodeMessage.character_count_size = {
  9: {
    1:10,
    2:9,
    4:8,
  },
  26: {
    1:12,
    2:11,
    4:16,
  },
  40: {
    1:14,
    2:13,
    4:16,
  }
}

QRCodeMessage.getVersion = function getVersion(){
  const versions = QRCodeMessage.versions[this.ecl];

  for(let version in versions){
    if(versions[version][this.type] >= this.message.length){
      return version;
    }
  }
}

QRCodeMessage.encode = {};

QRCodeMessage.encode.header = function header(){
  let size;

  for(let version in QRCodeMessage.character_count_size){
    if(Number(version) > this.version){
      size = QRCodeMessage.character_count_size[version][this.type];
      break;
    }
  }

  this.codewords.setBits(this.type          , 4   );
  this.codewords.setBits(this.message.length, size);
}

QRCodeMessage.encode.numeric = function numeric(){
  this.version = QRCodeMessage.getVersion.call(this);
  
  QRCodeMessage.encode.header.call(this);

  for(let i = 0; i < this.message.length; i+=3){
    const substring = this.message.substring(i, i + 3);

    if(substring.length === 3){
      this.codewords.setBits(Number(substring),10);
    }

    if(substring.length === 2){
      this.codewords.setBits(Number(substring), 7);
    }

    if(substring.length === 1){
      this.codewords.setBits(Number(substring), 4);
    }
  }
}

QRCodeMessage.encode.alphanumeric = function alphanumeric(){
  this.version = QRCodeMessage.getVersion.call(this);
  
  QRCodeMessage.encode.header.call(this);

  for(let i = 0; i < this.message.length; i+=2){
    const a = QRCodeMessage.alphanumeric[this.message[i]];
    const b = QRCodeMessage.alphanumeric[this.message[i + 1]];

    if(b !== undefined){
      this.codewords.setBits(a * 45 + b, 11);
    } else {
      this.codewords.setBits(a, 6); 
    }
  }
};

QRCodeMessage.encode.bytes = function bytes(){
  this.version = QRCodeMessage.getVersion.call(this);

  QRCodeMessage.encode.header.call(this);

  const buffer = new TextEncoder().encode(this.message);

  for(let i = 0; i < buffer.length; i++){
    this.codewords.setBits(buffer[i], 8);
  }
}

function QRCodeMessage(message, ecl){
  this.ecl = ecl;
  this.message = message;
  this.codewords    = new BitWriter();

  if(QRCodeMessage.regexp.numeric     .test(message)){
    this.type = 1;    
    QRCodeMessage.encode.numeric     .call(this);
  }

  if(QRCodeMessage.regexp.alphanumeric.test(message) & !this.type){
    this.type = 2;
    QRCodeMessage.encode.alphanumeric.call(this);
  }
    
  if(!this.type){
    this.type = 4
    QRCodeMessage.encode.bytes       .call(this);
  }

  return new QRGroupString(this);
}

export default QRCodeMessage;